// App.js
import React, { useState, useEffect } from "react";
import MapComponent from "./MapComponent";
import BusTrendChart from "./BusTrendChart";

function App() {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  // Fetch buses every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://localhost:8000/buses");
        const data = await res.json();
        setBuses(data);
      } catch (err) {
        console.error("Error fetching buses:", err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 min
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ position: "relative", width: "100vw", height: "100vh" }}>
      <MapComponent buses={buses} />
      
      {/* Bottom left bus counters */}
      <div style={{
        position: "absolute",
        bottom: "10px",
        left: "10px",
        backgroundColor: "rgba(255,255,255,0.8)",
        padding: "10px",
        borderRadius: "8px",
        fontWeight: "bold"
      }}>
        Normal: {buses.filter(b => b.status === "normal").length} <br />
        Ghost: {buses.filter(b => b.status === "ghost").length} <br />
        Anomaly: {buses.filter(b => b.status === "anomaly").length}
      </div>

      {/* Chart toggle button */}
      <button 
        style={{
          position: "absolute",
          top: "10px",
          left: "10px",
          padding: "8px 12px",
          zIndex: 10
        }}
        onClick={() => setShowChart(!showChart)}
      >
        {showChart ? "Hide Chart" : "Show Chart"}
      </button>

      {showChart && <BusTrendChart buses={buses} />}
    </div>
  );
}

export default App;
